        const key = `${x + dx},${y + dy}`;
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }
  const next = new Set<string>();
  for (const [cell, count] of neighborCounts) {
    if (count === 3 || (count === 2 && living.has(cell))) {
      next.add(cell);
    }
  }
  return next;
};
```

